<body>
    <div class="title">3D ROTATING DONUT</divx>
    <div class="subtitle">SIMULATED WITH MATHEMATICAL EQUATIONS</divx>
    <canvas id="donutCanvas"></canvas>

    <script>
        const canvas = document.getElementById('donutCanvas');
        const ctx = canvas.getContext('2d');

        canvas.width = 800;
        canvas.height = 600;

        // Donut parameters
        const R = 1.5; // Major radius
        const r = 0.5; // Minor radius
        const resolution = 40;
        const rotationSpeed = 0.02;

        let theta = 0;
        let phi = 0;

        // Black and white color palette
        const colors = [
            '#FFFFFF', '#CCCCCC', '#AAAAAA', 
            '#888888', '#666666', '#444444'
        ];

        function project(x, y, z) {
            const scale = 200;
            const distance = 5;

            // Perspective projection
            const factor = distance / (distance + z);
            const px = x * factor * scale + canvas.width / 2;
            const py = y * factor * scale + canvas.height / 2;

            return { x: px, y: py, z: z };
        }

        function drawDonut() {
            // Clear canvas with a semi-transparent black for trail effect
            ctx.fillStyle = 'rgba(0, 0, 0, 0.1)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Create gradient background
            const gradient = ctx.createRadialGradient(
                canvas.width/2, canvas.height/2, 0,
                canvas.width/2, canvas.height/2, Math.max(canvas.width, canvas.height)/2
            );
            gradient.addColorStop(0, 'rgba(50, 50, 50, 0.3)');
            gradient.addColorStop(1, 'rgba(0, 0, 0, 0.8)');

            ctx.fillStyle = gradient;
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // --- Donut Drawing Logic ---
            const centerX = canvas.width / 2;
            const centerY = canvas.height / 2;
            const distance = Math.sqrt(theta) * R; // Radial distance for drawing 

            // Draw the main ring (outer edge)
            ctx.beginPath();
            ctx.arc(centerX, centerY, distance, 0, Math.PI * 2);
            ctx.fillStyle = colors[0]; // White
            ctx.fill();

            // Draw the inner hole (cutout)
            ctx.beginPath();
            ctx.arc(centerX, centerY, distance - r, 0, Math.PI * 2);
            ctx.fillStyle = 'rgba(0, 0, 0, 0.5)'; // Darker center for depth
            ctx.fill();

            // Draw internal details (simplified representation)
            ctx.strokeStyle = colors[1]; // Light gray ring
            ctx.lineWidth = 5;
            ctx.beginPath();
            ctx.arc(centerX, centerY, distance - r, 0, Math.PI * 2);
            ctx.stroke();
        }

        function animate() {
            theta += rotationSpeed;
            drawDonut();
            requestAnimationFrame(animate);
        }

        // Start the animation loop
        animate();

    </script>
</body>
